import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { localOrders } from '../services/api';
import { useAuth } from '../context/AuthContext';

const STATUS = {
  active:    { bg:'#198754', label:'✅ Active',    textColor:'#fff' },
  cancelled: { bg:'#dc3545', label:'❌ Cancelled', textColor:'#fff' },
};

const fmt = d => new Date(d).toLocaleString('en-IN', {
  day:'2-digit', month:'short', year:'numeric',
  hour:'2-digit', minute:'2-digit', hour12:true,
});

const OrdersPage = ({ onToast }) => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [orders,     setOrders]     = useState([]);
  const [expandedId, setExpandedId] = useState(null);
  const [filter,     setFilter]     = useState('all');

  const load = () => setOrders(localOrders.get());

  useEffect(() => {
    load();
    window.addEventListener('ordersUpdated', load);
    return () => window.removeEventListener('ordersUpdated', load);
  }, []);

  const handleCancel = (orderId, e) => {
    e.stopPropagation();
    if (!window.confirm(`Cancel order ${orderId}? This cannot be undone.`)) return;
    const sessionId = sessionStorage.getItem('u_session') || 'no-session';
    localOrders.cancel(orderId, user, sessionId);
    load();
    window.dispatchEvent(new Event('ordersUpdated'));
    onToast?.('Order cancelled', 'warning');
  };

  const filtered      = filter === 'all' ? orders : orders.filter(o => o.status === filter);
  const activeCount   = orders.filter(o => o.status === 'active').length;
  const cancelCount   = orders.filter(o => o.status === 'cancelled').length;
  const totalSpent    = orders.filter(o => o.status === 'active').reduce((s,o) => s + o.total, 0);

  if (orders.length === 0) return (
    <div className="text-center py-5">
      <div style={{ fontSize:'5rem' }}>📦</div>
      <h4 className="fw-bold mt-3">No orders yet</h4>
      <p className="text-muted small">Your placed orders will appear here</p>
      <button className="btn btn-warning fw-bold mt-2 px-4" onClick={() => navigate('/products')}>
        🛍️ Start Shopping
      </button>
    </div>
  );

  return (
    <div>
      {/* Header */}
      <div className="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
        <div>
          <h4 className="fw-bold mb-1">📦 My Orders</h4>
          <p className="text-muted small mb-0">All your placed orders — cancel anytime before delivery</p>
        </div>
        <button className="btn btn-warning btn-sm fw-semibold" onClick={() => navigate('/products')}>
          🛍️ Shop More
        </button>
      </div>

      {/* KPI cards — responsive 2-col on mobile */}
      <div className="row g-2 mb-4">
        {[
          { icon:'📦', label:'Total Orders', value:orders.length,                     color:'primary' },
          { icon:'✅', label:'Active',       value:activeCount,                        color:'success' },
          { icon:'❌', label:'Cancelled',    value:cancelCount,                        color:'danger'  },
          { icon:'💰', label:'Total Spent',  value:`₹${totalSpent.toLocaleString('en-IN')}`, color:'warning' },
        ].map((c,i) => (
          <div key={i} className="col-6 col-md-3">
            <div className={`card border-0 shadow-sm border-top border-4 border-${c.color} text-center py-3`}>
              <div style={{ fontSize:'1.6rem' }}>{c.icon}</div>
              <div className={`fw-bold text-${c.color}`} style={{ fontSize:'1.3rem' }}>{c.value}</div>
              <div className="small text-muted">{c.label}</div>
            </div>
          </div>
        ))}
      </div>

      {/* Filter tabs */}
      <div className="d-flex gap-2 mb-3 flex-wrap">
        {[
          { key:'active',    label:`✅ Active (${activeCount})`      },
          { key:'cancelled', label:`❌ Cancelled (${cancelCount})`   },

        ].map(f => (
          <button key={f.key}
            className={`btn btn-sm fw-semibold ${filter===f.key ? 'btn-dark':'btn-outline-secondary'}`}
            onClick={() => setFilter(f.key)}>
            {f.label}
          </button>
        ))}
      </div>

      {/* Orders list */}
      <div className="d-flex flex-column gap-3">
        {filtered.length === 0 && (
          <div className="text-center py-4 text-muted">No orders in this filter</div>
        )}
        {filtered.map(order => {
          const st = STATUS[order.status] || STATUS.active;
          const isExpanded = expandedId === order.orderId;

          return (
            <div key={order.orderId}
              className={`card border-0 shadow-sm ${order.status==='cancelled' ? 'opacity-75' : ''}`}
              style={{ cursor:'pointer', transition:'box-shadow 0.2s' }}>

              {/* Order header — clickable */}
              <div className="card-body" onClick={() => setExpandedId(isExpanded ? null : order.orderId)}>
                <div className="d-flex justify-content-between align-items-start gap-2 flex-wrap">
                  {/* Left: icon + info */}
                  <div className="d-flex align-items-center gap-3">
                    <div className="rounded-circle d-flex align-items-center justify-content-center flex-shrink-0"
                      style={{ width:44, height:44, fontSize:'1.4rem',
                               background: order.status==='cancelled' ? '#dc354520':'#ffc10720' }}>
                      {order.status==='cancelled' ? '❌' : '📦'}
                    </div>
                    <div>
                      <div className="fw-bold small">Order #{order.orderId}</div>
                      <div className="text-muted" style={{ fontSize:'0.75rem' }}>
                        {order.items.length} item{order.items.length>1?'s':''} · {fmt(order.placedAt)}
                      </div>
                      {order.cancelledAt && (
                        <div className="text-danger" style={{ fontSize:'0.72rem' }}>Cancelled {fmt(order.cancelledAt)}</div>
                      )}
                    </div>
                  </div>

                  {/* Right: status + amount + cancel */}
                  <div className="d-flex align-items-center gap-2 flex-wrap">
                    <span className="badge px-2 py-1" style={{ background:st.bg, color:st.textColor, fontSize:'0.72rem' }}>
                      {st.label}
                    </span>
                    <span className="fw-bold text-success">₹{order.total.toLocaleString('en-IN')}</span>
                    {order.status==='active' && (
                      <button className="btn btn-outline-danger btn-sm py-0 px-2 fw-semibold"
                        style={{ fontSize:'0.78rem' }}
                        onClick={e => handleCancel(order.orderId, e)}>
                        🚫 Cancel
                      </button>
                    )}
                    <span className="text-muted small">{isExpanded ? '▲' : '▼'}</span>
                  </div>
                </div>

                {/* Product pills */}
                <div className="d-flex gap-2 mt-3 flex-wrap">
                  {order.items.map((item, i) => (
                    <div key={i} className="d-flex align-items-center gap-1 bg-light rounded-pill px-2 py-1"
                      style={{ fontSize:'0.72rem' }}>
                      <span>{item.emoji}</span>
                      <span className="text-truncate" style={{ maxWidth:110 }}>{item.name}</span>
                      <span className="text-muted">×{item.quantity}</span>
                    </div>
                  ))}
                </div>
              </div>

              {/* Expanded detail */}
              {isExpanded && (
                <div className="border-top bg-light p-3 p-md-4">
                  <div className="row g-3">

                    {/* Items table */}
                    <div className="col-12 col-md-7">
                      <h6 className="fw-bold mb-2">🛍️ Ordered Items</h6>
                      <div className="table-responsive rounded-3 overflow-hidden border">
                        <table className="table table-sm mb-0 align-middle">
                          <thead className="table-dark">
                            <tr>
                              <th>Product</th>
                              <th className="text-center" style={{ width:50 }}>Qty</th>
                              <th className="text-end" style={{ width:90 }}>Price</th>
                              <th className="text-end" style={{ width:100 }}>Total</th>
                            </tr>
                          </thead>
                          <tbody>
                            {order.items.map((item, i) => (
                              <tr key={i}>
                                <td>
                                  <div className="d-flex align-items-center gap-2">
                                    <span style={{ fontSize:'1.3rem', flexShrink:0 }}>{item.emoji}</span>
                                    <div>
                                      <div className="small fw-semibold">{item.name}</div>
                                      <div className="text-muted" style={{ fontSize:'0.65rem' }}>{item.category}</div>
                                    </div>
                                  </div>
                                </td>
                                <td className="text-center align-middle">{item.quantity}</td>
                                <td className="text-end align-middle small">₹{item.price.toLocaleString('en-IN')}</td>
                                <td className="text-end align-middle fw-bold text-success small">
                                  ₹{(item.price*item.quantity).toLocaleString('en-IN')}
                                </td>
                              </tr>
                            ))}
                          </tbody>
                          <tfoot style={{ background:'#fff3cd' }}>
                            <tr>
                              <td colSpan={3} className="fw-bold small">Grand Total</td>
                              <td className="text-end fw-bold text-success">₹{order.total.toLocaleString('en-IN')}</td>
                            </tr>
                          </tfoot>
                        </table>
                      </div>
                    </div>

                    {/* Delivery + cancel */}
                    <div className="col-12 col-md-5">
                      <h6 className="fw-bold mb-2">📍 Delivery Address</h6>
                      <div className="bg-white rounded-3 p-3 border mb-3">
                        <div className="small fw-bold">{order.delivery.name}</div>
                        <div className="small text-muted">{order.delivery.email}</div>
                        <div className="small mt-1">{order.delivery.address}</div>
                        <div className="small">{order.delivery.city} — {order.delivery.pin}</div>
                      </div>

                      {order.status==='active' ? (
                        <button className="btn btn-danger w-100 fw-semibold"
                          onClick={e => handleCancel(order.orderId, e)}>
                          🚫 Cancel This Order
                        </button>
                      ) : (
                        <div className="alert alert-danger small mb-0 py-2">
                          ❌ Cancelled on {fmt(order.cancelledAt)}
                        </div>
                      )}
                    </div>

                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default OrdersPage;
